// Native fixture generator for the OpenEXR-wasm coverage matrix. Builds small
// (<200 KB) committed EXRs exercising every decode path plus a large PIZ for
// the decode benchmark. Provenance: synthetically generated by this file
// against OpenEXR v3.4.9 / Imath v3.2.2. Built + run by build-native.sh.
//
//   gen <outdir>
//
// Produces: rgb-zip-half-64x48.exr, rgb-piz-float-64x48.exr,
//           luma-chroma-64x48.exr, deep-32x32.exr, htj2k-64x48.exr,
//           tiled-zip-half-64x48.exr, and (large, uncommitted)
//           rgb-piz-half-1024x1024.exr for benchmarking.

#include <cmath>
#include <string>
#include <vector>

#include <ImfOutputFile.h>
#include <ImfTiledOutputFile.h>
#include <ImfRgbaFile.h>
#include <ImfDeepScanLineOutputFile.h>
#include <ImfChannelList.h>
#include <ImfFrameBuffer.h>
#include <ImfDeepFrameBuffer.h>
#include <ImfHeader.h>
#include <ImfArray.h>
#include <ImfPartType.h>
#include <half.h>

using namespace Imf;
using namespace Imath;

static float wave(int x, int y, int c) {
  return 0.5f + 0.5f * std::sin((x * 0.21f + y * 0.13f) + c * 2.1f);
}

// Flat RGB half, chosen compression.
static void writeFlatHalf(const std::string& path, int w, int h, Compression comp) {
  Array2D<half> R(h, w), G(h, w), B(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      R[y][x] = wave(x, y, 0);
      G[y][x] = wave(x, y, 1);
      B[y][x] = wave(x, y, 2);
    }
  Header hd(w, h);
  hd.compression() = comp;
  hd.channels().insert("R", Channel(HALF));
  hd.channels().insert("G", Channel(HALF));
  hd.channels().insert("B", Channel(HALF));
  OutputFile file(path.c_str(), hd);
  FrameBuffer fb;
  fb.insert("R", Slice(HALF, (char*)&R[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("G", Slice(HALF, (char*)&G[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("B", Slice(HALF, (char*)&B[0][0], sizeof(half), sizeof(half) * w));
  file.setFrameBuffer(fb);
  file.writePixels(h);
}

// Flat RGB float, chosen compression (exercises the f32 output path).
static void writeFlatFloat(const std::string& path, int w, int h, Compression comp) {
  Array2D<float> R(h, w), G(h, w), B(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      R[y][x] = wave(x, y, 0);
      G[y][x] = wave(x, y, 1);
      B[y][x] = wave(x, y, 2);
    }
  Header hd(w, h);
  hd.compression() = comp;
  hd.channels().insert("R", Channel(FLOAT));
  hd.channels().insert("G", Channel(FLOAT));
  hd.channels().insert("B", Channel(FLOAT));
  OutputFile file(path.c_str(), hd);
  FrameBuffer fb;
  fb.insert("R", Slice(FLOAT, (char*)&R[0][0], sizeof(float), sizeof(float) * w));
  fb.insert("G", Slice(FLOAT, (char*)&G[0][0], sizeof(float), sizeof(float) * w));
  fb.insert("B", Slice(FLOAT, (char*)&B[0][0], sizeof(float), sizeof(float) * w));
  file.setFrameBuffer(fb);
  file.writePixels(h);
}

// Luminance-chroma: RgbaOutputFile with WRITE_YC stores Y/RY/BY subsampled.
static void writeLumaChroma(const std::string& path, int w, int h) {
  Array2D<Rgba> px(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x)
      px[y][x] = Rgba(wave(x, y, 0), wave(x, y, 1), wave(x, y, 2), 1.0f);
  RgbaOutputFile file(path.c_str(), w, h, WRITE_YC);
  file.setFrameBuffer(&px[0][0], 1, w);
  file.writePixels(h);
}

// Tiled ZIP half (exercises the flat-tiled read path).
static void writeTiledHalf(const std::string& path, int w, int h) {
  Array2D<half> R(h, w), G(h, w), B(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      R[y][x] = wave(x, y, 0);
      G[y][x] = wave(x, y, 1);
      B[y][x] = wave(x, y, 2);
    }
  Header hd(w, h);
  hd.compression() = ZIP_COMPRESSION;
  hd.channels().insert("R", Channel(HALF));
  hd.channels().insert("G", Channel(HALF));
  hd.channels().insert("B", Channel(HALF));
  hd.setTileDescription(TileDescription(16, 16, ONE_LEVEL));
  TiledOutputFile file(path.c_str(), hd);
  FrameBuffer fb;
  fb.insert("R", Slice(HALF, (char*)&R[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("G", Slice(HALF, (char*)&G[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("B", Slice(HALF, (char*)&B[0][0], sizeof(half), sizeof(half) * w));
  file.setFrameBuffer(fb);
  file.writeTiles(0, file.numXTiles() - 1, 0, file.numYTiles() - 1);
}

// HTJ2K compression (OpenEXR 3.4 + OpenJPH) — the whole point of the pivot.
static void writeHtj2k(const std::string& path, int w, int h) {
  Array2D<half> R(h, w), G(h, w), B(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      R[y][x] = wave(x, y, 0);
      G[y][x] = wave(x, y, 1);
      B[y][x] = wave(x, y, 2);
    }
  Header hd(w, h);
  hd.compression() = HTJ2K32_COMPRESSION;
  hd.channels().insert("R", Channel(HALF));
  hd.channels().insert("G", Channel(HALF));
  hd.channels().insert("B", Channel(HALF));
  OutputFile file(path.c_str(), hd);
  FrameBuffer fb;
  fb.insert("R", Slice(HALF, (char*)&R[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("G", Slice(HALF, (char*)&G[0][0], sizeof(half), sizeof(half) * w));
  fb.insert("B", Slice(HALF, (char*)&B[0][0], sizeof(half), sizeof(half) * w));
  file.setFrameBuffer(fb);
  file.writePixels(h);
}

// Deep scanline: 1-2 premultiplied RGBA samples per pixel at varying Z.
static void writeDeep(const std::string& path, int w, int h) {
  Header hd(w, h);
  hd.setType(DEEPSCANLINE);
  hd.compression() = ZIPS_COMPRESSION;
  hd.channels().insert("R", Channel(FLOAT));
  hd.channels().insert("G", Channel(FLOAT));
  hd.channels().insert("B", Channel(FLOAT));
  hd.channels().insert("A", Channel(FLOAT));
  hd.channels().insert("Z", Channel(FLOAT));

  Array2D<unsigned int> counts(h, w);
  Array2D<float*> Rp(h, w), Gp(h, w), Bp(h, w), Ap(h, w), Zp(h, w);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      unsigned int n = ((x + y) % 3 == 0) ? 2u : 1u;
      counts[y][x] = n;
      Rp[y][x] = new float[n]; Gp[y][x] = new float[n]; Bp[y][x] = new float[n];
      Ap[y][x] = new float[n]; Zp[y][x] = new float[n];
      // Back sample (larger Z) written FIRST to prove the decoder sorts by Z.
      for (unsigned int s = 0; s < n; ++s) {
        float a = (n == 2 && s == 0) ? 0.5f : 1.0f;  // front sample semi-transparent
        Rp[y][x][s] = a * wave(x, y, s);
        Gp[y][x][s] = a * wave(x, y, s + 1);
        Bp[y][x][s] = a * wave(x, y, s + 2);
        Ap[y][x][s] = a;
        Zp[y][x][s] = (n == 2) ? (s == 0 ? 10.0f : 1.0f) : 5.0f;  // s0 is BEHIND s1
      }
    }

  DeepScanLineOutputFile file(path.c_str(), hd);
  DeepFrameBuffer fb;
  fb.insertSampleCountSlice(Slice(UINT, (char*)&counts[0][0], sizeof(unsigned int),
                                  sizeof(unsigned int) * w));
  auto add = [&](const char* n, Array2D<float*>& p) {
    fb.insert(n, DeepSlice(FLOAT, (char*)&p[0][0], sizeof(float*),
                           sizeof(float*) * w, sizeof(float)));
  };
  add("R", Rp); add("G", Gp); add("B", Bp); add("A", Ap); add("Z", Zp);
  file.setFrameBuffer(fb);
  file.writePixels(h);
  for (int y = 0; y < h; ++y)
    for (int x = 0; x < w; ++x) {
      delete[] Rp[y][x]; delete[] Gp[y][x]; delete[] Bp[y][x];
      delete[] Ap[y][x]; delete[] Zp[y][x];
    }
}

int main(int argc, char** argv) {
  std::string dir = (argc > 1) ? argv[1] : ".";
  auto p = [&](const char* n) { return dir + "/" + n; };
  writeFlatHalf(p("rgb-zip-half-64x48.exr"), 64, 48, ZIP_COMPRESSION);
  writeFlatFloat(p("rgb-piz-float-64x48.exr"), 64, 48, PIZ_COMPRESSION);
  writeLumaChroma(p("luma-chroma-64x48.exr"), 64, 48);
  writeTiledHalf(p("tiled-zip-half-64x48.exr"), 64, 48);
  writeHtj2k(p("htj2k-half-64x48.exr"), 64, 48);
  writeDeep(p("deep-rgba-32x32.exr"), 32, 32);
  writeFlatHalf(p("rgb-piz-half-1024x1024.exr"), 1024, 1024, PIZ_COMPRESSION);
  return 0;
}
